777	\begin{lemma}\leanok
778	[Linear lifting of \texttt{left\_adjoint\_additive}]
779	  \label{lemma:Adjunction_left_adjoint_linear}
780	  \lean{CategoryTheory.Adjunction.left_adjoint_linear}
781	  Let $F : \mathcal{C} \to \mathcal{D}$ be a functor between $R$-linear preadditive categories with right adjoint $G$. If $G$ is $R$-linear (and additive), then $F$ is $R$-linear.
782	\end{lemma}
783	
784	\begin{proof}
785	  \leanok
786	  Mirrors Mathlib's \lstinline{left_adjoint_additive}. By $\mathtt{homEquiv}$-injectivity, $F.\mathtt{map}\,(r \cdot f) = r \cdot F.\mathtt{map}\,f$ reduces to an equality on the right side of the adjunction, where $\mathtt{simp}\,[\mathtt{adj.homEquiv\_unit}]$ rewrites both sides via unit naturality and the default simp lemmas \lstinline{Linear.smul_comp} and \lstinline{Linear.comp_smul}.
787	\end{proof}
788	
789	\begin{lemma}\leanok
790	[Right-adjoint version]
791	  \label{lemma:Adjunction_right_adjoint_linear}
792	  \lean{CategoryTheory.Adjunction.right_adjoint_linear}
793	  Dual of Lemma~\ref{lemma:Adjunction_left_adjoint_linear}: if $F$ is $R$-linear (and additive), then $G$ is $R$-linear.
794	\end{lemma}
795	
796	\begin{proof}
797	  \leanok
798	  Same proof shape, using $\mathtt{adj.homEquiv\_counit}$ in place of $\mathtt{adj.homEquiv\_unit}$.
799	\end{proof}
