801	\begin{theorem}\leanok
802	[Linear hom-equivalence from an adjunction]
803	  \label{def:Adjunction_homLinearEquiv}
804	  \lean{CategoryTheory.Adjunction.homLinearEquiv}
805	  \uses{lemma:Adjunction_left_adjoint_linear}
806	  Let $\mathtt{adj} : F \dashv G$ between $R$-linear preadditive categories with $F.\mathtt{Additive}$, $G.\mathtt{Additive}$, $G.\mathtt{Linear}\,R$. Then for all objects $X$ and $Y$, the additive equivalence $\mathtt{adj.homAddEquiv}\,X\,Y$ upgrades to a $\LinearEquiv$ over $R$:
807	  \[
808	    (F.\mathtt{obj}\,X \to Y) \;\equivl{R}\; (X \to G.\mathtt{obj}\,Y).
809	  \]
810	\end{theorem}
811	
812	\begin{proof}
813	  \leanok
814	  Build the $\LinearEquiv$ structure by overriding the \lstinline{map_smul'} field of \lstinline{adj.homAddEquiv}: the $\mathtt{change}$ tactic exposes the underlying $\mathtt{homEquiv}$ form, after which $\mathtt{simp}\,[\mathtt{adj.homEquiv\_unit}]$ closes via the same naturality argument as Lemma~\ref{lemma:Adjunction_left_adjoint_linear}. The \lstinline{haveI} line that establishes $F.\mathtt{Linear}\,R$ via Lemma~\ref{lemma:Adjunction_left_adjoint_linear} is load-bearing.
815	\end{proof}
